import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class PruferCode {
    public static int[] pruferEncode(int n, int[][] edges) {
        if (n <= 2) {
            return new int[0];
        }

        List<List<Integer>> adjacency = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adjacency.add(new ArrayList<>());
        }
        int[] degree = new int[n];

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            adjacency.get(u).add(v);
            adjacency.get(v).add(u);
            degree[u]++;
            degree[v]++;
        }

        int[] result = new int[n - 2];
        for (int i = 0; i < n - 2; i++) {
            int leaf = 0;
            while (leaf < n && degree[leaf] != 1) {
                leaf++;
            }
            int neighbor = 0;
            for (int next : adjacency.get(leaf)) {
                if (degree[next] > 0) {
                    neighbor = next;
                    break;
                }
            }
            result[i] = neighbor;
            degree[leaf]--;
            degree[neighbor]--;
        }

        return result;
    }
}

import java.util.PriorityQueue

fun pruferEncode(n: Int, edges: Array<IntArray>): IntArray {
    if (n <= 2) {
        return intArrayOf()
    }

    val adjacency = Array(n) { mutableListOf<Int>() }
    val degree = IntArray(n)

    for (edge in edges) {
        if (edge.size >= 2) {
            val u = edge[0]
            val v = edge[1]
            adjacency[u].add(v)
            adjacency[v].add(u)
            degree[u]++
            degree[v]++
        }
    }

    val leaves = PriorityQueue<Int>()
    for (node in 0 until n) {
        if (degree[node] == 1) {
            leaves.add(node)
        }
    }

    val result = IntArray(n - 2)
    for (index in 0 until n - 2) {
        val leaf = leaves.poll()
        val neighbor = adjacency[leaf].first { degree[it] > 0 }
        result[index] = neighbor
        degree[leaf]--
        degree[neighbor]--
        if (degree[neighbor] == 1) {
            leaves.add(neighbor)
        }
    }

    return result
}

func pruferEncode(_ n: Int, _ edges: [[Int]]) -> [Int] {
    if n <= 2 { return [] }

    var adjacency = Array(repeating: [Int](), count: n)
    var degree = Array(repeating: 0, count: n)

    for edge in edges where edge.count >= 2 {
        let u = edge[0]
        let v = edge[1]
        adjacency[u].append(v)
        adjacency[v].append(u)
        degree[u] += 1
        degree[v] += 1
    }

    var code: [Int] = []
    for _ in 0..<(n - 2) {
        var leaf = 0
        while leaf < n && degree[leaf] != 1 {
            leaf += 1
        }
        if leaf == n { break }

        let neighbor = adjacency[leaf].first { degree[$0] > 0 } ?? 0
        code.append(neighbor)
        degree[leaf] -= 1
        degree[neighbor] -= 1
    }

    return code
}
